const fs = require('fs');
const transcriptPath = $input.first().json.transcript_path;

let transcript;
try {
  transcript = fs.readFileSync(transcriptPath, 'utf8');
} catch (e) {
  throw new Error(`Cannot read transcript at ${transcriptPath}: ${e.message}`);
}

return [{
  json: {
    ...$input.first().json,
    transcript: transcript,
    filename: transcriptPath.split('/').pop(),
    char_count: transcript.length,
    line_count: transcript.split('\n').length
  }
}];

// Call Ollama API to extract structured memo from transcript
const http = require('http');
const data = $input.first().json;

const prompt = `You are a data extraction assistant. Extract structured account information from this demo/sales call transcript. Return ONLY a single valid JSON object with these fields:
- company_name (string)
- contact_name (string)
- contact_role (string or null)
- phone (string or null)
- email (string or null)
- industry (string)
- company_size (string or null)
- current_challenges (array of strings)
- services_of_interest (array of strings)
- budget_range (string or null)
- timeline (string or null)
- business_hours (object: {days, open, close})
- call_handling_preferences (object)
- special_instructions (array of strings)
- questions_or_unknowns (array of strings)

IMPORTANT: If a field is not mentioned, set to null. Do NOT guess.

Transcript:
${data.transcript.substring(0, 6000)}`;

const body = JSON.stringify({
  model: data.model,
  prompt: prompt,
  stream: false,
  options: { temperature: 0.1 }
});

// Parse URL manually (URL class not available in n8n sandbox)
const urlParts = data.ollama_url.replace('http://', '').split(':');
const hostname = urlParts[0];
const port = urlParts[1] ? parseInt(urlParts[1]) : 80;

const result = await new Promise((resolve, reject) => {
  const req = http.request({
    hostname: hostname,
    port: port,
    path: '/api/generate',
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    timeout: 120000
  }, (res) => {
    let responseData = '';
    res.on('data', chunk => responseData += chunk);
    res.on('end', () => {
      try {
        resolve(JSON.parse(responseData));
      } catch (e) {
        reject(new Error('Failed to parse Ollama response: ' + responseData.substring(0, 500)));
      }
    });
  });
  req.on('error', reject);
  req.on('timeout', () => reject(new Error('Ollama request timed out')));
  req.write(body);
  req.end();
});

return [{ json: { ...data, ollama_response: result.response || '' } }];

const raw = $input.first().json;
const response = raw.ollama_response;

let memo;
try {
  const jsonMatch = response.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    memo = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found in Ollama response');
  }
} catch (e) {
  return [{ json: { error: `Parse failed: ${e.message}`, raw_response: response.substring(0, 1000) } }];
}

const crypto = require('crypto');
const slug = (memo.company_name || 'unknown').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
const hash = crypto.createHash('md5').update(memo.company_name || 'unknown').digest('hex').substring(0, 6);
const account_id = `${slug}-${hash}`;

const required = ['company_name', 'contact_name', 'industry'];
const missing = required.filter(f => !memo[f]);

return [{
  json: {
    account_id,
    company_name: memo.company_name,
    memo,
    validation: missing.length === 0 ? 'PASSED' : `MISSING: ${missing.join(', ')}`,
    fields_extracted: Object.keys(memo).length
  }
}];

const memo = $input.first().json.memo;
const account_id = $input.first().json.account_id;

const company = memo.company_name || 'Unknown Company';
const contact = memo.contact_name || 'the team';
const industry = memo.industry || 'general business';
const challenges = (memo.current_challenges || []).join(', ') || 'general inquiries';
const services = (memo.services_of_interest || []).join(', ') || 'our services';

const hours = memo.business_hours || {};
const bh = `${hours.days || 'Monday-Friday'}, ${hours.open || '9:00 AM'} - ${hours.close || '5:00 PM'}`;

const system_prompt = `You are Clara, an AI voice assistant for ${company}.

Company: ${company}
Industry: ${industry}
Primary Contact: ${contact}
Business Hours: ${bh}

Key Services: ${services}
Customer Challenges: ${challenges}

During business hours:
- Answer calls professionally for ${company}
- Help with scheduling and service inquiries
- Collect caller name, phone, and reason for calling
- Transfer to ${contact} for complex issues

Outside business hours:
- Inform callers of business hours (${bh})
- Offer to take a message
- Handle emergencies per protocol

Critical Rules:
- Never fabricate information about ${company}
- Always confirm before transferring calls
- Be professional, friendly, and empathetic`;

const agent_spec = {
  agent_name: `${company} - Clara AI`,
  account_id,
  version: 'v1',
  system_prompt,
  voice_style: { tone: 'professional and friendly', pace: 'moderate', personality: 'helpful assistant' },
  source: 'demo_call'
};

return [{
  json: {
    account_id,
    company_name: company,
    memo,
    agent_spec,
    prompt_length: system_prompt.length
  }
}];

const fs = require('fs');
const path = require('path');
const data = $input.first().json;
const baseDir = `/home/node/outputs/accounts/${data.account_id}/v1`;

try {
  fs.mkdirSync(baseDir, { recursive: true });
  fs.writeFileSync(path.join(baseDir, 'memo.json'), JSON.stringify(data.memo, null, 2));
  fs.writeFileSync(path.join(baseDir, 'agent_spec.json'), JSON.stringify(data.agent_spec, null, 2));

  return [{
    json: {
      status: 'SUCCESS',
      account_id: data.account_id,
      company: data.company_name,
      output_dir: baseDir,
      files_saved: ['memo.json', 'agent_spec.json'],
      message: `Pipeline A complete for ${data.company_name}`
    }
  }];
} catch (e) {
  return [{ json: { status: 'ERROR', error: e.message } }];
}
